'use strict';

function slugStats(input) {
  if (typeof input !== 'string') {
    throw new TypeError('slugStats: input must be a string');
  }

  const tokens = input
    .toLowerCase()
    .split(/[^a-z0-9]+/)
    .filter((token) => token.length > 0);

  const unique = new Set(tokens);

  return {
    words: tokens.length,
    uniqueWords: unique.size,
    slug: tokens.join('-'),
  };
}

module.exports = { slugStats };
